#include <bits/stdc++.h>
using namespace std;

// 最长上升子序列 (LIS) - O(n^2)
int lis_n2(vector<int>& a) {
    int n = a.size();
    vector<int> dp(n, 1); // dp[i]: 以a[i]结尾的LIS长度
    int ans = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (a[j] < a[i]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
        ans = max(ans, dp[i]);
    }
    return ans;
}

// 最长上升子序列 (LIS) - O(nlogn)
int lis_nlogn(vector<int>& a) {
    vector<int> d; // d[k]: 长度为k的上升子序列的最小末尾值
    for (int x : a) {
        auto it = lower_bound(d.begin(), d.end(), x);
        if (it == d.end()) d.push_back(x);
        else *it = x;
    }
    return d.size();
}

// 最长公共子序列 (LCS) - O(nm)
int lcs(string& s, string& t) {
    int n = s.size(), m = t.size();
    vector<vector<int>> dp(n+1, vector<int>(m+1, 0));
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            if (s[i-1] == t[j-1]) {
                dp[i][j] = dp[i-1][j-1] + 1;
            } else {
                dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
            }
        }
    }
    return dp[n][m];
}

// 数字三角形 - 自底向上
int triangle(vector<vector<int>>& a) {
    int n = a.size();
    vector<vector<int>> dp = a;
    for (int i = n-2; i >= 0; i--) {
        for (int j = 0; j <= i; j++) {
            dp[i][j] += max(dp[i+1][j], dp[i+1][j+1]);
        }
    }
    return dp[0][0];
}

int main() {
    // 示例用法
    vector<int> arr = {10, 9, 2, 5, 3, 7, 101, 18};
    cout << "LIS (O(n^2)): " << lis_n2(arr) << endl;
    cout << "LIS (O(nlogn)): " << lis_nlogn(arr) << endl;

    string s = "abcde", t = "ace";
    cout << "LCS: " << lcs(s, t) << endl;

    vector<vector<int>> tri = {{7}, {3,8}, {8,1,0}, {2,7,4,4}, {4,5,2,6,5}};
    cout << "Triangle max path: " << triangle(tri) << endl;

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// 01背包模板
int knapsack_01(int n, int W, vector<int>& wt, vector<int>& val) {
    vector<int> dp(W + 1, 0);
    for (int i = 0; i < n; i++) {
        for (int j = W; j >= wt[i]; j--) {  // 逆序枚举容量
            dp[j] = max(dp[j], dp[j - wt[i]] + val[i]);
        }
    }
    return dp[W];
}

// 完全背包模板
int knapsack_complete(int n, int W, vector<int>& wt, vector<int>& val) {
    vector<int> dp(W + 1, 0);
    for (int i = 0; i < n; i++) {
        for (int j = wt[i]; j <= W; j++) {  // 正序枚举容量
            dp[j] = max(dp[j], dp[j - wt[i]] + val[i]);
        }
    }
    return dp[W];
}

// 多重背包模板（二进制优化）
int knapsack_multiple(int n, int W, vector<int>& wt, vector<int>& val, vector<int>& cnt) {
    vector<pair<int, int>> items;  // (重量, 价值)
    for (int i = 0; i < n; i++) {
        int k = 1;
        while (cnt[i] > 0) {
            int take = min(k, cnt[i]);
            items.push_back({wt[i] * take, val[i] * take});
            cnt[i] -= take;
            k <<= 1;
        }
    }
    // 转化为01背包
    vector<int> dp(W + 1, 0);
    for (auto& [w, v] : items) {
        for (int j = W; j >= w; j--) {
            dp[j] = max(dp[j], dp[j - w] + v);
        }
    }
    return dp[W];
}

int main() {
    // 示例用法
    int n = 5, W = 10;
    vector<int> wt = {2, 3, 4, 5, 6};
    vector<int> val = {3, 4, 5, 6, 7};
    vector<int> cnt = {1, 2, 3, 4, 5};

    cout << "01背包结果: " << knapsack_01(n, W, wt, val) << endl;
    cout << "完全背包结果: " << knapsack_complete(n, W, wt, val) << endl;
    cout << "多重背包结果: " << knapsack_multiple(n, W, wt, val, cnt) << endl;

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const int N = 310;
int n;
int a[N], prefix[N];
int dp[N][N]; // dp[l][r] 表示合并区间 [l, r] 的最小代价

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        prefix[i] = prefix[i - 1] + a[i]; // 前缀和用于快速求区间和
    }

    // 初始化dp数组
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (i == j) dp[i][j] = 0; // 单个石子不需要合并
            else dp[i][j] = 1e9; // 初始化为极大值
        }
    }

    // 区间DP核心：枚举区间长度
    for (int len = 2; len <= n; len++) { // 区间长度从2开始
        for (int l = 1; l + len - 1 <= n; l++) { // 左端点
            int r = l + len - 1; // 右端点
            // 枚举分割点k，将区间[l, r]分成[l, k]和[k+1, r]
            for (int k = l; k < r; k++) {
                // 状态转移：合并[l, k]的代价 + 合并[k+1, r]的代价 + 合并这两堆的代价
                dp[l][r] = min(dp[l][r], dp[l][k] + dp[k + 1][r] + prefix[r] - prefix[l - 1]);
            }
        }
    }

    cout << dp[1][n] << endl;
    return 0;
}

/*
区间DP模板总结：
1. 状态定义：dp[l][r] 表示区间 [l, r] 的最优解
2. 初始化：对角线元素（单个元素）通常有初始值
3. 枚举顺序：
   - 先枚举区间长度 len
   - 再枚举左端点 l
   - 计算右端点 r = l + len - 1
   - 最后枚举分割点 k
4. 状态转移：根据具体问题设计
5. 答案：通常是 dp[1][n] 或类似形式
*/

