#include <bits/stdc++.h>
using namespace std;

const int INF = 0x3f3f3f3f;
const int MAXN = 20; // 最大城市数
const int MAXM = (1 << 20) + 5; // 最大状态数

int n; // 城市数量
int dist[MAXN][MAXN]; // 距离矩阵
int dp[MAXM][MAXN]; // dp[state][i]: 当前访问状态为state，最后停留在城市i的最小代价

// 旅行商问题模板
int tsp() {
    memset(dp, INF, sizeof(dp));
    dp[1][0] = 0; // 从城市0出发，状态为000...001

    for (int mask = 1; mask < (1 << n); mask++) {
        for (int i = 0; i < n; i++) {
            if (dp[mask][i] == INF) continue;
            if (!(mask & (1 << i))) continue;

            // 尝试从i走到j
            for (int j = 0; j < n; j++) {
                if (mask & (1 << j)) continue; // j已经访问过
                int newMask = mask | (1 << j);
                dp[newMask][j] = min(dp[newMask][j], dp[mask][i] + dist[i][j]);
            }
        }
    }

    // 计算回到起点的最小代价
    int ans = INF;
    int fullMask = (1 << n) - 1;
    for (int i = 1; i < n; i++) {
        if (dp[fullMask][i] != INF && dist[i][0] != INF) {
            ans = min(ans, dp[fullMask][i] + dist[i][0]);
        }
    }
    return ans;
}

// 棋盘放置问题模板（n皇后变种）
int boardDP(int n, int m) {
    vector<int> validStates;
    // 预处理所有合法行状态（没有相邻的1）
    for (int s = 0; s < (1 << m); s++) {
        if (!(s & (s << 1))) {
            validStates.push_back(s);
        }
    }

    vector<vector<int>> dp(n + 1, vector<int>(1 << m, 0));
    dp[0][0] = 1;

    for (int i = 1; i <= n; i++) {
        for (int cur : validStates) {
            for (int prev : validStates) {
                // 检查列冲突和斜向冲突
                if ((cur & prev) == 0 && ((cur << 1) & prev) == 0 && (cur & (prev << 1)) == 0) {
                    dp[i][cur] += dp[i - 1][prev];
                }
            }
        }
    }

    int ans = 0;
    for (int s : validStates) {
        ans += dp[n][s];
    }
    return ans;
}

int main() {
    // 旅行商问题示例
    cin >> n;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> dist[i][j];
        }
    }
    cout << tsp() << endl;

    // 棋盘问题示例
    int rows, cols;
    cin >> rows >> cols;
    cout << boardDP(rows, cols) << endl;

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// 数位DP模板
// 问题：统计区间[L,R]中满足某种条件的数字个数
// 通常转化为 count(R) - count(L-1)

long long dp[20][2][2]; // 状态数组，维度根据具体问题调整
vector<int> digits;     // 存储数字的每一位

// 记忆化搜索
// pos: 当前处理到的位置（从高位到低位）
// tight: 是否受到上界限制（1表示受限）
// lead: 是否有前导零（1表示有前导零）
// 其他状态根据具体问题添加
long long dfs(int pos, int tight, int lead) {
    // 递归终止条件：处理完所有数位
    if (pos == digits.size()) {
        // 根据具体问题返回结果
        // 例如：统计非零数字个数，有前导零不算
        return lead ? 0 : 1;
    }

    // 记忆化：如果已经计算过，直接返回
    if (dp[pos][tight][lead] != -1) {
        return dp[pos][tight][lead];
    }

    long long res = 0;
    // 确定当前位可以取的数字范围
    int limit = tight ? digits[pos] : 9;

    for (int d = 0; d <= limit; d++) {
        // 计算新的状态
        int new_tight = tight && (d == limit);
        int new_lead = lead && (d == 0);

        // 根据具体问题添加条件判断
        // 例如：不能出现连续的数字
        // if (!lead && abs(d - prev_digit) <= 1) continue;

        // 递归处理下一位
        res += dfs(pos + 1, new_tight, new_lead);
    }

    return dp[pos][tight][lead] = res;
}

// 将数字x分解为数位数组
long long solve(long long x) {
    if (x < 0) return 0;

    digits.clear();
    while (x) {
        digits.push_back(x % 10);
        x /= 10;
    }
    reverse(digits.begin(), digits.end());

    // 初始化dp数组为-1
    memset(dp, -1, sizeof(dp));

    // 从最高位开始搜索
    return dfs(0, 1, 1);
}

int main() {
    long long L, R;
    cin >> L >> R;

    // 计算[0,R]的答案减去[0,L-1]的答案
    long long ans = solve(R) - solve(L - 1);
    cout << ans << endl;

    return 0;
}

