// 单调队列优化DP模板
#include <bits/stdc++.h>
using namespace std;

const int N = 1e6 + 10;
int dp[N], a[N];
int n, k;

deque<int> q; // 存储下标

int main() {
    cin >> n >> k;
    for (int i = 1; i <= n; i++) cin >> a[i];

    // 初始化
    dp[1] = a[1];
    q.push_back(1);

    for (int i = 2; i <= n; i++) {
        // 维护队列范围：窗口大小k
        while (!q.empty() && i - q.front() > k) q.pop_front();

        // 状态转移：dp[i] = min(dp[j]) + a[i], j在[i-k, i-1]
        dp[i] = dp[q.front()] + a[i];

        // 维护单调性（递增队列求最小值）
        while (!q.empty() && dp[q.back()] >= dp[i]) q.pop_back();
        q.push_back(i);
    }

    cout << dp[n] << endl;
    return 0;
}

// 斜率优化模板（以最小值为例）
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
const int N = 1e6 + 10;
ll dp[N], sum[N], a[N];
int n;

deque<int> q;

// 斜率计算
inline ll X(int j) { return sum[j]; }
inline ll Y(int j) { return dp[j] + sum[j] * sum[j]; }
inline double slope(int i, int j) {
    if (X(i) == X(j)) return 1e18;
    return (double)(Y(i) - Y(j)) / (X(i) - X(j));
}

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        sum[i] = sum[i-1] + a[i];
    }

    q.push_back(0);
    for (int i = 1; i <= n; i++) {
        // 维护队首：斜率单调性
        while (q.size() >= 2 && slope(q[0], q[1]) <= 2 * sum[i]) q.pop_front();

        int j = q.front();
        // 状态转移：dp[i] = dp[j] + (sum[i]-sum[j])^2
        dp[i] = dp[j] + (sum[i] - sum[j]) * (sum[i] - sum[j]);

        // 维护队尾：下凸包性质
        while (q.size() >= 2 && slope(q[q.size()-2], q.back()) >= slope(q.back(), i)) q.pop_back();
        q.push_back(i);
    }

    cout << dp[n] << endl;
    return 0;
}
